export default function* applicationConnectToGitSaga(
  action: GitArtifactPayloadAction<ConnectSuccessPayload>,
) {
  const { artifactDef, responseData: destArtifact } = action.payload;

  if (artifactDef.artifactType !== GitArtifactType.Application) return;

  const pageId: string = yield select(getCurrentPageId);

  yield put(fetchPageAction(pageId));

  const branch = destArtifact?.gitApplicationMetadata?.branchName;

  if (branch) {
    const newUrl = addBranchParam(branch);

    history.replace(newUrl);
  }

  const currentApplication: GitApplicationArtifact = yield select(
    getCurrentApplication,
  );

  if (currentApplication) {
    currentApplication.lastDeployedAt = new Date().toISOString();
    yield put({
      type: ReduxActionTypes.FETCH_APPLICATION_SUCCESS,
      payload: currentApplication,
    });
  }

  yield put(
    gitArtifactActions.initGitForEditor({
      artifactDef,
      artifact: destArtifact,
    }),
  );
}

import { useCallback, useEffect, useState } from "react";

export default function useActiveHoverIndex(
  currentBranch: string | undefined,
  filteredBranches: Array<string>,
  isCreateNewBranchInputValid: boolean,
) {
  const effectiveLength = isCreateNewBranchInputValid
    ? filteredBranches.length
    : filteredBranches.length - 1;

  const [activeHoverIndex, setActiveHoverIndexInState] = useState(0);
  const setActiveHoverIndex = useCallback(
    (index: number) => {
      if (index < 0) setActiveHoverIndexInState(effectiveLength);
      else if (index > effectiveLength) setActiveHoverIndexInState(0);
      else setActiveHoverIndexInState(index);
    },
    [effectiveLength],
  );

  useEffect(
    function activeHoverIndexEffect() {
      const activeBranchIdx = filteredBranches.indexOf(currentBranch || "");

      if (activeBranchIdx !== -1) {
        setActiveHoverIndex(
          isCreateNewBranchInputValid ? activeBranchIdx + 1 : activeBranchIdx,
        );
      } else {
        setActiveHoverIndex(0);
      }
    },
    [
      currentBranch,
      filteredBranches,
      isCreateNewBranchInputValid,
      setActiveHoverIndex,
    ],
  );

  return { activeHoverIndex, setActiveHoverIndex };
}

